export class StubEmbedder{dimensions;constructor(e=64){this.dimensions=e}async embed(e){return this.computeEmbedding(e)}async embedBatch(e){return e.map(t=>this.computeEmbedding(t))}computeEmbedding(e){const t=new Array(this.dimensions).fill(0);for(let s=0;s<e.length;s++){const d=e.charCodeAt(s)%this.dimensions;t[d]+=1}const r=Math.sqrt(t.reduce((s,i)=>s+i*i,0));if(r>0)for(let s=0;s<t.length;s++)t[s]=t[s]/r;return t}}export class OpenAIEmbedder{dimensions;apiKey;baseUrl;model;constructor(e){this.apiKey=e.apiKey??process.env.OPENAI_API_KEY??"",this.baseUrl=e.baseUrl??"https://api.openai.com/v1",this.model=e.model,this.dimensions=e.dimensions}async embed(e){const t=await this.embedBatch([e]);if(t.length===0)throw new Error("Embedding API returned empty results");return t[0]}async embedBatch(e){const t=await fetch(`${this.baseUrl}/embeddings`,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${this.apiKey}`},body:JSON.stringify({model:this.model,input:e,dimensions:this.dimensions})});if(!t.ok)throw new Error(`OpenAI embeddings API error: ${t.status} ${t.statusText}`);return(await t.json()).data.map(s=>s.embedding)}}export function createEmbedder(n){switch(n.type){case"stub":return new StubEmbedder(n.dimensions);case"openai":return new OpenAIEmbedder(n);default:throw new Error(`Unknown embedder type: ${n.type}`)}}
